const get = require('get-value');
const logger = require('../../utils/logger');
const { ERROR_MESSAGES } = require('../../utils/constants');
const { Error403, Error500 } = require('../../utils/httpErrors');

/**
 * @description Enable 2FA on a Gladys Plus account, by validating a code generated by the user's 2FA app.
 * @param {string} accessToken - Access token returned by the Gateway login when 2FA is not enabled yet.
 * @param {string} twoFactorCode - The 6-digits code generated by the 2FA app.
 * @returns {Promise<object>} Resolve when 2FA is enabled.
 * @example
 * enableTwoFactor('access-token', '123456');
 */
async function enableTwoFactor(accessToken, twoFactorCode) {
  try {
    const result = await this.gladysGatewayClient.enableTwoFactor(accessToken, twoFactorCode);
    return result;
  } catch (e) {
    logger.debug(e);
    const status = get(e, 'response.status');
    if (status) {
      throw new Error403();
    }
    throw new Error500(ERROR_MESSAGES.NO_CONNECTED_TO_THE_INTERNET);
  }
}

module.exports = {
  enableTwoFactor,
};
